/// <summary>
/// Extension of the <c>AgreementLineHistory</c> table for the ETGSPAIN model.
/// </summary>
[ExtensionOf(tableStr(AgreementLineHistory))]
public final class AgreementLineHistoryETGSPAIN_Extension
{
}

Method.Source:
/// <summary>
/// Initializes an <c>AgreementLineHistory</c> record from an <c>AgreementLine</c> record.
/// </summary>
/// <param name="_line">The <c>AgreementLine</c> record.</param>
public void initFromAgreementLine(AgreementLine _line)
{
    next initFromAgreementLine(_line);

    if(CompanyInfo::find().ETGSpanishCompany == NoYes::Yes)
    {
        this.ETGSPAINPurchSalesAgreementLinecode     = _line.ETGSPAINLineCode;
        this.ETGSPAINPurchExecutionFromDate          = _line.ETGSPAINPurchExecutionFromDate;
        this.ETGSPAINPurchExecutionDueDate           = _line.ETGSPAINPurchExecutionDueDate;

        this.ETGSPAINItemTextPrintoutOfAgreements    = _line.inventTable().ETGSPAINItemTextPrintoutOfAgreements;
        this.ETGSPAINLineCode                        = _line.ETGSPAINLineCode;
    }
}
